+    #[test]
+    fn excluded_panes_without_filter_reports_panes_excluded() {
+        let now = now_ms();
+        let ctx = SearchExplainContext {
+            pane_filter: None,
+            panes: vec![
+                PaneExplainInfo {
+                    pane_id: 1,
+                    observed: true,
+                    ignore_reason: None,
+                    domain: "local".to_string(),
+                    last_seen_at: now,
+                },
+                PaneExplainInfo {
+                    pane_id: 2,
+                    observed: false,
+                    ignore_reason: Some("excluded".to_string()),
+                    domain: "local".to_string(),
+                    last_seen_at: now,
+                },
+                PaneExplainInfo {
+                    pane_id: 3,
+                    observed: false,
+                    ignore_reason: Some("excluded".to_string()),
+                    domain: "local".to_string(),
+                    last_seen_at: now,
+                },
+            ],
+            indexing_stats: vec![PaneIndexingInfo {
+                pane_id: 1,
+                segment_count: 100,
+                total_bytes: 5000,
+                last_segment_at: Some(now),
+                fts_row_count: 100,
+                fts_consistent: true,
+            }],
+            ..empty_context()
+        };
+        let result = explain_search(&ctx);
+        assert!(result.reasons.iter().any(|r| r.code == "PANES_EXCLUDED"));
+        assert_eq!(result.ignored_panes, 2);
+    }
