+    #[test]
+    fn multiple_gaps_across_panes() {
+        let now = now_ms();
+        let ctx = SearchExplainContext {
+            panes: vec![
+                PaneExplainInfo {
+                    pane_id: 1,
+                    observed: true,
+                    ignore_reason: None,
+                    domain: "local".to_string(),
+                    last_seen_at: now,
+                },
+                PaneExplainInfo {
+                    pane_id: 2,
+                    observed: true,
+                    ignore_reason: None,
+                    domain: "local".to_string(),
+                    last_seen_at: now,
+                },
+            ],
+            indexing_stats: vec![
+                PaneIndexingInfo {
+                    pane_id: 1,
+                    segment_count: 50,
+                    total_bytes: 2500,
+                    last_segment_at: Some(now),
+                    fts_row_count: 50,
+                    fts_consistent: true,
+                },
+                PaneIndexingInfo {
+                    pane_id: 2,
+                    segment_count: 30,
+                    total_bytes: 1500,
+                    last_segment_at: Some(now),
+                    fts_row_count: 30,
+                    fts_consistent: true,
+                },
+            ],
+            gaps: vec![
+                GapInfo {
+                    pane_id: 1,
+                    seq_before: 10,
+                    seq_after: 20,
+                    reason: "restart".to_string(),
+                    detected_at: now,
+                },
+                GapInfo {
+                    pane_id: 2,
+                    seq_before: 5,
+                    seq_after: 15,
+                    reason: "timeout".to_string(),
+                    detected_at: now,
+                },
+            ],
+            earliest_segment_at: Some(now - 3_600_000),
+            latest_segment_at: Some(now),
+            now_ms: now,
+            ..empty_context()
+        };
+        let result = explain_search(&ctx);
+        let gap_reason = result
+            .reasons
+            .iter()
+            .find(|r| r.code == "CAPTURE_GAPS")
+            .unwrap();
+        assert!(gap_reason.summary.contains("2 capture gap(s)"));
+        assert!(gap_reason.summary.contains("2 pane(s)"));
+    }
